CREATE OR REPLACE FUNCTION fpb_get_spp_member_monthly (as_memno char ,adt_dfrom timestamp(0) ,adt_dto timestamp(0) ) RETURNS bigint AS $body$
DECLARE

li_count integer;
ldc_amount  bigint;

BEGIN
			select  sum(recept_amount)
      into STRICT  ldc_amount
			from 		sc_com_m_receipt
			where ( membership_no = as_memno)
      and ( sc_com_m_receipt.receipt_date between adt_dfrom and adt_dto )
			and ( sc_com_m_receipt.receipt_status = '0' )
			and ( sc_com_m_receipt.money_type_id not in ( 'CLR' , 'TNL' ) );

    return coalesce(ldc_amount,0);
  exception when others then return 0;

end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
